import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details to the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save text-white',
    highlight: 'primary',
    color: '#8E2DE2',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "ItemCode": "ITEM001",
      "CategoryId": 1,
      "ProductId": 2,
      "DesignId": 3,
      "PurityId": 4,
      "GrossWeight": "10.50",
      "NetWeight": "9.80",
      "BoxNumber": "BOX001",
      "Status": "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of the product to Active or Sold based on the RFID Number.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-edit text-white',
    highlight: 'info',
    color: '#4A00E0',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "Status": "Sold" // Can be "Sold" or "Active"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all records from the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-search text-white',
    highlight: 'primary',
    color: '#06beb6',
    sampleBody: {
      "ClientCode": "" // Will be filled dynamically
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Delete one or more items using ClientCode, RFID Number, or ItemCode.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash text-white',
    highlight: 'danger',
    color: '#FF416C',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumbers": ["RFID123456789", "RFID987654321"],
      "ItemCodes": ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [token, setToken] = useState('');
  const [dashboardError, setDashboardError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    console.log('Dashboard useEffect running');
    const storedToken = localStorage.getItem('token');
    const storedUserInfo = localStorage.getItem('userInfo');
    
    console.log('Stored token:', storedToken);
    console.log('Stored userInfo:', storedUserInfo);
    
    if (!storedToken) {
      console.log('No token found, redirecting to login');
      setDashboardError('No token found. Please login again.');
      navigate('/login');
      return;
    }

    // Validate token and extract client code
    try {
      console.log('Attempting to parse token');
      const tokenData = JSON.parse(atob(storedToken.split('.')[1]));
      console.log('Parsed token data:', tokenData);
      
      if (!tokenData.ClientCode) {
        console.log('No client code found in token');
        setDashboardError('Invalid token: No client code found.');
        throw new Error('Invalid token: No client code found');
      }
      setToken(storedToken);
      
      if (storedUserInfo) {
        console.log('Parsing stored user info');
        const parsedUserInfo = JSON.parse(storedUserInfo);
        if (parsedUserInfo.ClientCode !== tokenData.ClientCode) {
          console.log('Updating client code in user info');
          parsedUserInfo.ClientCode = tokenData.ClientCode;
          localStorage.setItem('userInfo', JSON.stringify(parsedUserInfo));
        }
        setUserInfo(parsedUserInfo);
      } else {
        console.log('Creating new user info');
        const userInfo = {
          Username: tokenData.sub,
          ClientCode: tokenData.ClientCode
        };
        localStorage.setItem('userInfo', JSON.stringify(userInfo));
        setUserInfo(userInfo);
      }
    } catch (err) {
      console.error('Token validation error:', err);
      setDashboardError('Token validation error: ' + err.message);
      localStorage.removeItem('token');
      localStorage.removeItem('userInfo');
      navigate('/login');
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    let sampleBodyCopy = JSON.parse(JSON.stringify(api.sampleBody));
    
    // Handle both array and object request bodies
    if (Array.isArray(sampleBodyCopy)) {
      sampleBodyCopy = sampleBodyCopy.map(item => ({
        ...item,
        ClientCode: userInfo?.ClientCode || ''
      }));
    } else {
      sampleBodyCopy = {
        ...sampleBodyCopy,
        ClientCode: userInfo?.ClientCode || ''
      };
    }
    
    setRequestBody(JSON.stringify(sampleBodyCopy, null, 2));
    setResponse('');
    setError('');
  };

  const isAuthenticated = !!token && !!userInfo?.ClientCode;

  const handleSendRequest = async () => {
    if (!selectedApi) return;
    if (!isAuthenticated) {
      setError('You must be logged in to test the API.');
      toast.error('You must be logged in to test the API.', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      return;
    }
    setLoading(true);
    setError('');
    setResponse('');
    try {
      const config = {
        headers: {
          'Content-Type': 'application/json'
        }
      };
      if (selectedApi.authRequired) {
        if (!token) {
          throw new Error('Authentication token is required for this endpoint');
        }
        config.headers['Authorization'] = `Bearer ${token}`;
      }
      const url = `${selectedApi.baseUrl}/${selectedApi.endpoint}`;
      let parsedBody;
      try {
        parsedBody = JSON.parse(requestBody);
      } catch (e) {
        throw new Error('Invalid JSON in request body');
      }
      if (!parsedBody.ClientCode) {
        throw new Error('ClientCode is required');
      }
      const result = await axios.post(url, parsedBody, config);
      if (result.data.Status === false) {
        throw new Error(result.data.Message || 'Operation failed');
      }
      setResponse(JSON.stringify(result.data, null, 2));
      toast.success(result.data.Message || 'API request successful!', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage, {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      if (err.response?.status === 401) {
        toast.error('Authentication failed. Please login again.', {
          theme: 'colored',
          style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
        });
        localStorage.removeItem('token');
        localStorage.removeItem('userInfo');
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      height: 'calc(100vh - 52px)', // Adjusted for new header height
      display: 'flex',
      flexDirection: 'column',
      background: '#fff',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
      padding: 0
    }}>
      <Header userInfo={userInfo} />
      <ToastContainer />
      {dashboardError && (
        <div className="alert alert-danger m-4" style={{
          borderRadius: '12px',
          border: 'none',
          background: 'rgba(220, 53, 69, 0.1)',
          color: '#dc3545',
          boxShadow: '0 4px 10px rgba(0, 0, 0, 0.05)'
        }}>
          <i className="fas fa-exclamation-circle me-2"></i>
          {dashboardError}
        </div>
      )}
      
      <div className="container py-4" style={{ flex: 1 }}>
        <div className="row">
          <div className="col-md-4 mb-4">
            <div className="card border-0 shadow-sm" style={{ 
              background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)', 
              borderRadius: 16,
              boxShadow: '0 10px 25px rgba(0, 0, 0, 0.07)'
            }}>
              <div className="card-header border-0" style={{ 
                borderTopLeftRadius: 16, 
                borderTopRightRadius: 16,
                background: 'rgba(255, 255, 255, 0.9)',
                padding: '1.2rem'
              }}>
                <h5 className="mb-0 d-flex align-items-center" style={{ 
                  fontFamily: 'Poppins, Montserrat, Arial, sans-serif', 
                  fontWeight: 600,
                  color: '#333'
                }}>
                  <i className="fas fa-list-alt me-2" style={{
                    background: 'linear-gradient(45deg, #667eea, #764ba2)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    fontSize: '1.3rem'
                  }}></i>
                  API Endpoints
                </h5>
              </div>
              <div className="list-group list-group-flush p-2">
                {API_ENDPOINTS.map((api, index) => (
                  <button
                    key={index}
                    className={`list-group-item list-group-item-action d-flex align-items-center ${selectedApi?.endpoint === api.endpoint ? 'active' : ''}`}
                    style={{
                      border: 'none',
                      background: selectedApi?.endpoint === api.endpoint ? 
                        `linear-gradient(90deg, ${api.color} 0%, rgba(255,255,255,0.3) 100%)` : 
                        'rgba(255, 255, 255, 0.5)',
                      color: selectedApi?.endpoint === api.endpoint ? '#fff' : '#333',
                      fontWeight: 500,
                      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
                      transition: 'all 0.3s ease',
                      marginBottom: 6,
                      borderRadius: 10,
                      padding: '12px 15px'
                    }}
                    onClick={() => handleApiSelect(api)}
                  >
                    <div className="d-flex align-items-center w-100">
                      <div style={{
                        width: 30,
                        height: 30,
                        borderRadius: '50%',
                        background: selectedApi?.endpoint === api.endpoint ? 
                          'rgba(255, 255, 255, 0.2)' : 
                          `linear-gradient(135deg, ${api.color} 0%, rgba(255,255,255,0.8) 150%)`,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        marginRight: 12,
                        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)'
                      }}>
                        <i className={`${api.icon}`} style={{
                          color: selectedApi?.endpoint === api.endpoint ? '#fff' : '#fff',
                          fontSize: '0.9rem'
                        }}></i>
                      </div>
                      <span>{api.name}</span>
                    </div>
                  </button>
                ))}
              </div>
            </div>
            
            <div className="card border-0 shadow-sm mt-4" style={{ 
              background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)', 
              borderRadius: 16,
              padding: '20px',
              boxShadow: '0 10px 25px rgba(0, 0, 0, 0.07)'
            }}>
              <div className="d-flex align-items-center mb-3">
                <div style={{
                  width: 40,
                  height: 40,
                  borderRadius: '50%',
                  background: 'linear-gradient(45deg, #4776E6, #8E54E9)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: 15,
                  boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)'
                }}>
                  <i className="fas fa-info-circle text-white"></i>
                </div>
                <h5 className="mb-0" style={{ fontWeight: 600, color: '#333' }}>Learn More</h5>
              </div>
              
              <p className="text-muted mb-3" style={{ fontSize: '0.95rem' }}>
                Visit our RFID Integration page to learn how to integrate RFID in your third-party applications.
              </p>
              
              <a href="/rfid-integration" className="btn btn-sm w-100" style={{
                background: 'linear-gradient(45deg, #4776E6, #8E54E9)',
                color: 'white',
                border: 'none',
                borderRadius: 10,
                padding: '8px',
                fontWeight: 500,
                boxShadow: '0 4px 10px rgba(71, 118, 230, 0.2)',
                transition: 'all 0.3s'
              }}>
                <i className="fas fa-plug me-2"></i>
                Integration Guide
              </a>
            </div>
          </div>
          <div className="col-md-8">
            {selectedApi ? (
              <div className="card border-0 shadow-sm" style={{ 
                borderRadius: 16,
                background: '#fff'
              }}>
                <div className="card-header border-0 d-flex align-items-center" style={{ 
                  background: '#F9FAFB',
                  padding: '1rem 1.5rem',
                  borderTopLeftRadius: 16,
                  borderTopRightRadius: 16
                }}>
                  <div className="me-2 px-2 py-1" style={{
                    background: '#7C3AED',
                    color: '#fff',
                    borderRadius: '4px',
                    fontSize: '0.8rem',
                    fontWeight: 600
                  }}>POST</div>
                  <h5 className="mb-0" style={{ 
                    fontSize: '1.1rem',
                    fontWeight: 600,
                    color: '#111827'
                  }}>{selectedApi.name}</h5>
                </div>
                
                <div className="card-body p-4">
                  <div className="mb-4">
                    <h6 className="mb-2" style={{ 
                      color: '#111827',
                      fontSize: '0.9rem',
                      fontWeight: 600
                    }}>Description</h6>
                    <p style={{ 
                      color: '#6B7280',
                      fontSize: '0.9rem',
                      marginBottom: 0
                    }}>{selectedApi.description}</p>
                  </div>
                  
                  <div className="mb-4">
                    <h6 className="mb-2" style={{ 
                      color: '#111827',
                      fontSize: '0.9rem',
                      fontWeight: 600
                    }}>Request Body</h6>
                    <div style={{ 
                      background: '#F9FAFB',
                      borderRadius: '8px',
                      padding: '1rem'
                    }}>
                      <textarea
                        className="form-control border-0"
                        value={requestBody}
                        onChange={(e) => setRequestBody(e.target.value)}
                        style={{ 
                          fontSize: '0.9rem',
                          background: 'transparent',
                          fontFamily: 'monospace',
                          resize: 'none',
                          height: 'auto',
                          minHeight: '200px'
                        }}
                      />
                    </div>
                  </div>
                  
                  <button
                    className="btn w-100"
                    onClick={handleSendRequest}
                    disabled={loading || !isAuthenticated}
                    style={{
                      background: '#7C3AED',
                      color: '#fff',
                      padding: '0.75rem',
                      borderRadius: '8px',
                      fontSize: '0.9rem',
                      fontWeight: 600,
                      border: 'none',
                      transition: 'all 0.2s'
                    }}
                    onMouseOver={e => {
                      e.currentTarget.style.background = '#6D28D9';
                    }}
                    onMouseOut={e => {
                      e.currentTarget.style.background = '#7C3AED';
                    }}
                  >
                    {loading ? (
                      <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                    ) : (
                      <>
                        <i className="fas fa-paper-plane me-2"></i>
                        Send Request
                      </>
                    )}
                  </button>
                  
                  {error && (
                    <div className="alert alert-danger mt-4 mb-0" style={{ 
                      fontSize: '0.9rem',
                      borderRadius: '8px'
                    }}>
                      {error}
                    </div>
                  )}
                  
                  {response && (
                    <div className="mt-4">
                      <h6 className="mb-2" style={{ 
                        color: '#111827',
                        fontSize: '0.9rem',
                        fontWeight: 600
                      }}>Response</h6>
                      <pre style={{ 
                        background: '#F9FAFB',
                        padding: '1rem',
                        borderRadius: '8px',
                        fontSize: '0.9rem',
                        margin: 0
                      }}>
                        <code>{response}</code>
                      </pre>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="card border-0 shadow-lg d-flex align-items-center justify-content-center w-100" style={{ 
                borderRadius: 16, 
                background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)', 
                minHeight: 'calc(100vh - 150px)',
                height: '100%',
                boxShadow: '0 15px 35px rgba(0, 0, 0, 0.1)'
              }}>
                <div className="text-center p-5">
                  <div style={{
                    width: 90,
                    height: 90,
                    borderRadius: '50%',
                    background: 'linear-gradient(45deg, #667eea 0%, #764ba2 100%)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    margin: '0 auto 20px',
                    boxShadow: '0 8px 20px rgba(102, 126, 234, 0.3)'
                  }}>
                    <i className="fas fa-book fa-2x text-white"></i>
                  </div>
                  
                  <h3 className="fw-bold mb-3" style={{ 
                    fontFamily: 'Poppins, Montserrat, Arial, sans-serif', 
                    color: '#333',
                    fontSize: '1.8rem',
                    verticalAlign: 'middle' 
                  }}>
                    <img 
                      src="/Logo/LSlogo.png" 
                      alt="Loyalstring" 
                      style={{ 
                        height: '48px',
                        marginRight: '10px',
                        verticalAlign: 'middle' 
                      }} 
                    />
                    RFID API
                  </h3>
                  
                  <p className="mb-4" style={{ 
                    color: '#666', 
                    fontSize: '1.1rem', 
                    maxWidth: '500px', 
                    margin: '0 auto' 
                  }}>
                    Select an API endpoint from the sidebar to view documentation and test the API.
                  </p>
                  
                  <div className="d-flex flex-wrap justify-content-center gap-3 mt-3">
                    {API_ENDPOINTS.map((api, index) => (
                      <button 
                        key={index}
                        className="btn btn-sm" 
                        style={{
                          background: `linear-gradient(45deg, ${api.color} 0%, ${api.color}99 100%)`,
                          color: 'white',
                          border: 'none',
                          borderRadius: '8px',
                          padding: '6px 12px',
                          margin: '5px',
                          fontWeight: 500,
                          boxShadow: `0 4px 10px ${api.color}33`,
                          transition: 'all 0.3s'
                        }}
                        onClick={() => handleApiSelect(api)}
                        onMouseOver={e => {
                          e.currentTarget.style.transform = 'translateY(-2px)';
                          e.currentTarget.style.boxShadow = `0 6px 15px ${api.color}55`;
                        }}
                        onMouseOut={e => {
                          e.currentTarget.style.transform = 'translateY(0)';
                          e.currentTarget.style.boxShadow = `0 4px 10px ${api.color}33`;
                        }}
                      >
                        <i className={`${api.icon} me-1`}></i>
                        {api.name.length > 20 ? api.name.substring(0, 18) + '...' : api.name}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      {/* Google Fonts for Poppins and Fira Mono */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&family=Fira+Mono&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Dashboard;
